@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """
    Download an invoice PDF by invoice ID.
    
    Prevents broken access control by verifying that the authenticated
    user owns the requested invoice before allowing download.
    """
    # Step 1: Get the authenticated user's ID
    authenticated_user_id = get_authenticated_user_id()
    if authenticated_user_id is None:
        return jsonify({"error": "Authentication required"}), 401

    # Step 2: Validate the invoice_id input
